function gerarId() {
return Date.now().toString(36) + Math.random().toString(36).substring(2, 9);
}
function formatarHora(timestamp) {
const data = new Date(timestamp);
const agora = new Date();
const diferenca = agora - data;
if (diferenca < 60000) return 'Agora';
if (diferenca < 3600000) {
const minutos = Math.floor(diferenca / 60000);
return `${minutos}min atrás`;
}
if (data.toDateString() === agora.toDateString()) {
return data.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
}
const ontem = new Date(agora);
ontem.setDate(ontem.getDate() - 1);
if (data.toDateString() === ontem.toDateString()) {
return 'Ontem';
}
return data.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' });
}
function escaparHtml(texto) {
const div = document.createElement('div');
div.textContent = texto;
return div.innerHTML;
}
async function copiarParaClipboard(texto) {
try {
await navigator.clipboard.writeText(texto);
return true;
} catch (erro) {
console.error('Erro ao copiar:', erro);
return false;
}
}
function rolarParaFinal(elemento) {
if (!elemento) return;
requestAnimationFrame(() => {
elemento.scrollTo({
top: elemento.scrollHeight,
behavior: 'smooth',
});
});
}
function debounce(funcao, atraso = 300) {
let timer;
return (...args) => {
clearTimeout(timer);
timer = setTimeout(() => funcao.apply(this, args), atraso);
};
}
function truncarTexto(texto, tamanhoMax = 40) {
if (!texto) return '';
if (texto.length <= tamanhoMax) return texto;
return texto.substring(0, tamanhoMax) + '...';
}
function gerarTituloConversa(mensagem) {
const limpo = mensagem.replace(/\n/g, ' ').trim();
return truncarTexto(limpo, 50);
}
function obterContainerToast() {
let container = document.querySelector('.toast-container');
if (!container) {
container = document.createElement('div');
container.className = 'toast-container';
document.body.appendChild(container);
}
return container;
}
function toastSucesso(mensagem) {
exibirToast(mensagem, 'toast-sucesso');
}
function toastErro(mensagem) {
exibirToast(mensagem, 'toast-erro');
}
function toastInfo(mensagem) {
exibirToast(mensagem, 'toast-info');
}
function exibirToast(mensagem, classe) {
const container = obterContainerToast();
const toast = document.createElement('div');
toast.className = `toast ${classe}`;
toast.textContent = mensagem;
container.appendChild(toast);
setTimeout(() => {
if (toast.parentElement) {
toast.remove();
}
}, 3000);
}
