const painelLoja = {
_elementos: null,
_produtoEditandoId: null,
/**
* Inicializa o painel da loja
*/
inicializar() {
this._elementos = {
modal: document.getElementById('modal-loja'),
botaoAbrir: document.getElementById('botao-abrir-loja'),
botaoFechar: document.getElementById('fechar-modal-loja'),
listaProdutos: document.getElementById('loja-lista-produtos'),
seletorPersonalidade: document.getElementById('seletor-personalidade'),
// Formulário de Configuração Geral
inputNomeLoja: document.getElementById('loja-nome-input'),
inputCupom: document.getElementById('loja-cupom-input'),
inputGarantia: document.getElementById('loja-garantia-input'),
// Formulário de Produto
formProduto: document.getElementById('form-produto-loja'),
inputProdNome: document.getElementById('prod-nome'),
inputProdPreco: document.getElementById('prod-preco'),
inputProdPromo: document.getElementById('prod-promo'),
inputProdPrazo: document.getElementById('prod-prazo'),
inputProdDesc: document.getElementById('prod-desc'),
inputProdGatilhos: document.getElementById('prod-gatilhos'),
botaoCancelarEdicao: document.getElementById('botao-cancelar-edicao-produto'),
botaoSalvarProduto: document.getElementById('botao-salvar-produto'),
};
this._configurarEventos();
this._carregarConfiguracoes();
this._renderizarProdutos();
this._renderizarPersonalidades();
},
/**
* Configura event listeners
*/
_configurarEventos() {
this._elementos.botaoAbrir.addEventListener('click', () => this.abrir());
this._elementos.botaoFechar.addEventListener('click', () => this.fechar());
// Fechar ao clicar no overlay
this._elementos.modal.addEventListener('click', (e) => {
if (e.target === this._elementos.modal) this.fechar();
});
// Fechar com ESC
document.addEventListener('keydown', (e) => {
if (e.key === 'Escape' && this._elementos.modal.style.display !== 'none') {
this.fechar();
}
});
// Salvar configurações gerais ao sair dos inputs
const salvarConfig = () => this._salvarConfiguracoesGerais();
this._elementos.inputNomeLoja.addEventListener('change', salvarConfig);
this._elementos.inputCupom.addEventListener('change', salvarConfig);
this._elementos.inputGarantia.addEventListener('change', salvarConfig);
// Cancelar edição de produto
this._elementos.botaoCancelarEdicao.addEventListener('click', () => this._cancelarEdicao());
// Submeter formulário de produto
this._elementos.formProduto.addEventListener('submit', (e) => {
e.preventDefault();
this._salvarProduto();
});
},
/**
* Abre o modal
*/
abrir() {
this._elementos.modal.style.display = 'flex';
this._carregarConfiguracoes();
this._renderizarProdutos();
this._cancelarEdicao();
},
/**
* Fecha o modal
*/
fechar() {
this._elementos.modal.style.display = 'none';
},
/**
* Carrega as configurações gerais da loja nos campos
*/
_carregarConfiguracoes() {
const config = bancoDeDadosServico.obterConfiguracoesLoja();
this._elementos.inputNomeLoja.value = config.nomeLoja;
this._elementos.inputCupom.value = config.cupomDesconto;
this._elementos.inputGarantia.value = config.garantiaPadrao;
},
/**
* Salva as configurações gerais da loja
*/
_salvarConfiguracoesGerais() {
const config = bancoDeDadosServico.obterConfiguracoesLoja();
config.nomeLoja = this._elementos.inputNomeLoja.value.trim() || CONFIG_LOJA_PADRAO.nomeLoja;
config.cupomDesconto = this._elementos.inputCupom.value.trim().toUpperCase();
config.garantiaPadrao = this._elementos.inputGarantia.value.trim();
bancoDeDadosServico.salvarConfiguracoesLoja(config);
toastSucesso('Configurações da loja atualizadas!');
},
/**
* Renderiza a lista de produtos cadastrados
*/
_renderizarProdutos() {
const produtos = bancoDeDadosServico.obterProdutos();
if (produtos.length === 0) {
this._elementos.listaProdutos.innerHTML = `
<div class="lista-vazia" style="padding: 24px; text-align: center;">
<p style="color: var(--cor-texto-secundario); font-size: 13px;">Nenhum produto cadastrado na loja</p>
</div>
`;
return;
}
this._elementos.listaProdutos.innerHTML = produtos.map(prod => `
<div class="produto-card">
<div class="produto-card-info">
<span class="produto-card-nome">${escaparHtml(prod.nome)}</span>
<div class="produto-card-valores">
<span class="produto-card-preco">R$ ${prod.precoPromocional ? prod.precoPromocional.toFixed(2) : prod.preco.toFixed(2)}</span>
${prod.precoPromocional ? `<span style="text-decoration: line-through; opacity: 0.4; font-size: 11px;">R$ ${prod.preco.toFixed(2)}</span>` : ''}
<span class="produto-card-prazo">🚚 ${escaparHtml(prod.prazoEntrega.split('|')[0].trim())}</span>
</div>
</div>
<div class="produto-card-acoes">
<button class="botao-acao-produto" onclick="painelLoja.editarProduto('${prod.id}')" title="Editar produto">
✏️
</button>
<button class="botao-acao-produto deletar" onclick="painelLoja.deletarProduto('${prod.id}')" title="Excluir produto">
🗑️
</button>
</div>
</div>
`).join('');
},
/**
* Renderiza as opções de personalidades de vendas
*/
_renderizarPersonalidades() {
const personalidades = bancoDeDadosServico.obterPersonalidades();
const config = bancoDeDadosServico.obterConfiguracoesLoja();
const ativa = config.personalidadeAtiva;
this._elementos.seletorPersonalidade.innerHTML = Object.values(personalidades).map(p => {
const selecionada = p.id === ativa;
return `
<div class="opcao-personalidade-loja ${selecionada ? 'selecionada' : ''}"
onclick="painelLoja.selecionarPersonalidade('${p.id}')">
<span class="personalidade-titulo">
${p.id === 'persuasivo_extremo' ? '🐺' : p.id === 'consultivo' ? '🤝' : p.id === 'direto' ? '🎯' : '🏷️'}
${p.nome}
</span>
<span class="personalidade-descricao">${p.descricao}</span>
</div>
`;
}).join('');
},
/**
* Altera a personalidade de vendas da IA
*/
selecionarPersonalidade(id) {
const config = bancoDeDadosServico.obterConfiguracoesLoja();
config.personalidadeAtiva = id;
bancoDeDadosServico.salvarConfiguracoesLoja(config);
this._renderizarPersonalidades();
const personalidades = bancoDeDadosServico.obterPersonalidades();
toastSucesso(`Modo de vendas alterado: ${personalidades[id.toUpperCase()].nome}`);
},
/**
* Inicia a edição de um produto
*/
editarProduto(id) {
const produtos = bancoDeDadosServico.obterProdutos();
const produto = produtos.find(p => p.id === id);
if (!produto) return;
this._produtoEditandoId = id;
this._elementos.inputProdNome.value = produto.nome;
this._elementos.inputProdPreco.value = produto.preco;
this._elementos.inputProdPromo.value = produto.precoPromocional || '';
this._elementos.inputProdPrazo.value = produto.prazoEntrega;
this._elementos.inputProdDesc.value = produto.descricao;
this._elementos.inputProdGatilhos.value = produto.gatilhosVenda || '';
// UI Feedback
this._elementos.botaoSalvarProduto.textContent = 'Atualizar Produto';
this._elementos.botaoCancelarEdicao.style.display = 'block';
toastInfo(`Editando: ${produto.nome}`);
},
/**
* Cancela a edição e limpa formulário
*/
_cancelarEdicao() {
this._produtoEditandoId = null;
this._elementos.formProduto.reset();
this._elementos.botaoSalvarProduto.textContent = 'Cadastrar Produto';
this._elementos.botaoCancelarEdicao.style.display = 'none';
},
/**
* Exclui um produto
*/
deletarProduto(id) {
if (!confirm('Deseja realmente excluir este produto?')) return;
const deletado = bancoDeDadosServico.deletarProduto(id);
if (deletado) {
toastSucesso('Produto excluído com sucesso!');
this._renderizarProdutos();
if (this._produtoEditandoId === id) this._cancelarEdicao();
} else {
toastErro('Erro ao excluir produto');
}
},
/**
* Salva ou edita o produto
*/
_salvarProduto() {
const nome = this._elementos.inputProdNome.value.trim();
const preco = parseFloat(this._elementos.inputProdPreco.value);
const precoPromoRaw = this._elementos.inputProdPromo.value.trim();
const precoPromocional = precoPromoRaw ? parseFloat(precoPromoRaw) : null;
const prazoEntrega = this._elementos.inputProdPrazo.value.trim();
const descricao = this._elementos.inputProdDesc.value.trim();
const gatilhosVenda = this._elementos.inputProdGatilhos.value.trim();
if (!nome || isNaN(preco) || !prazoEntrega || !descricao) {
toastErro('Preencha os campos obrigatórios!');
return;
}
const produto = {
id: this._produtoEditandoId || 'prod_' + gerarId(),
nome,
preco,
precoPromocional,
prazoEntrega,
descricao,
gatilhosVenda
};
const sucesso = bancoDeDadosServico.salvarProduto(produto);
if (sucesso) {
toastSucesso(this._produtoEditandoId ? 'Produto atualizado!' : 'Produto cadastrado com sucesso!');
this._cancelarEdicao();
this._renderizarProdutos();
} else {
toastErro('Erro ao salvar produto');
}
}
};
/* File: scripts/componentes/chat.js */
/* ============================================
NEXCHAT - Componente Chat
Gerencia mensagens e interação principal
============================================ */
const chat = {
_elementos: null,
_conversaAtual: null,
_enviando: false,
/**
* Inicializa o chat
*/
inicializar() {
this._elementos = {
areaMensagens: document.getElementById('area-mensagens'),
containerMensagens: document.getElementById('container-mensagens'),
telaBemVindo: document.getElementById('tela-boas-vindas'),
campoMensagem: document.getElementById('campo-mensagem'),
botaoEnviar: document.getElementById('botao-enviar'),
contadorCaracteres: document.getElementById('contador-caracteres'),
};
this._configurarEventos();
this._restaurarConversaAtiva();
},
/**
* Configura event listeners
*/
_configurarEventos() {
// Enviar mensagem
this._elementos.botaoEnviar.addEventListener('click', () => this._enviarMensagem());
// Enter para enviar (Shift+Enter para nova linha)
this._elementos.campoMensagem.addEventListener('keydown', (e) => {
if (e.key === 'Enter' && !e.shiftKey) {
e.preventDefault();
this._enviarMensagem();
}
});
// Auto-resize do textarea
this._elementos.campoMensagem.addEventListener('input', () => {
this._autoResize();
this._atualizarBotaoEnviar();
});
// Sugestões na tela de boas-vindas
document.querySelectorAll('.sugestao-card').forEach(card => {
card.addEventListener('click', () => {
const prompt = card.getAttribute('data-prompt');
this._elementos.campoMensagem.value = prompt;
this._autoResize();
this._atualizarBotaoEnviar();
this._enviarMensagem();
});
});
},
/**
* Auto-resize do textarea
*/
_autoResize() {
const campo = this._elementos.campoMensagem;
campo.style.height = 'auto';
campo.style.height = Math.min(campo.scrollHeight, 200) + 'px';
// Atualiza contador
const total = campo.value.length;
this._elementos.contadorCaracteres.textContent = `${total} / 10000`;
},
/**
* Atualiza estado do botão enviar
*/
_atualizarBotaoEnviar() {
const temTexto = this._elementos.campoMensagem.value.trim().length > 0;
this._elementos.botaoEnviar.disabled = !temTexto || this._enviando;
},
/**
* Restaura a conversa ativa salva
*/
_restaurarConversaAtiva() {
const idAtiva = armazenamentoServico.obterConversaAtiva();
if (idAtiva) {
this.carregarConversa(idAtiva);
}
},
/**
* Cria uma nova conversa
*/
novaConversa() {
this._conversaAtual = null;
armazenamentoServico.salvarConversaAtiva('');
this._mostrarBoasVindas();
this._elementos.campoMensagem.value = '';
this._elementos.campoMensagem.focus();
this._autoResize();
this._atualizarBotaoEnviar();
barraLateral.renderizar();
},
/**
* Carrega uma conversa existente
*/
carregarConversa(id) {
const conversas = armazenamentoServico.obterConversas();
const conversa = conversas.find(c => c.id === id);
if (!conversa) {
toastErro('Conversa não encontrada');
return;
}
this._conversaAtual = conversa;
armazenamentoServico.salvarConversaAtiva(id);
this._renderizarMensagens();
barraLateral.renderizar();
},
/**
* Mostra a tela de boas-vindas
*/
_mostrarBoasVindas() {
this._elementos.telaBemVindo.style.display = 'flex';
this._elementos.containerMensagens.style.display = 'none';
this._elementos.containerMensagens.innerHTML = '';
},
/**
* Esconde a tela de boas-vindas e mostra o chat
*/
_mostrarChat() {
this._elementos.telaBemVindo.style.display = 'none';
this._elementos.containerMensagens.style.display = 'flex';
},
/**
* Renderiza todas as mensagens da conversa ativa
*/
_renderizarMensagens() {
if (!this._conversaAtual || !this._conversaAtual.mensagens.length) {
this._mostrarBoasVindas();
return;
}
this._mostrarChat();
this._elementos.containerMensagens.innerHTML = '';
this._conversaAtual.mensagens.forEach(msg => {
this._adicionarMensagemAoDOM(msg);
});
rolarParaFinal(this._elementos.areaMensagens);
},
/**
* Adiciona uma mensagem no DOM
*/
_adicionarMensagemAoDOM(mensagem) {
const div = document.createElement('div');
const ehUsuario = mensagem.papel === 'user';
div.className = `mensagem ${ehUsuario ? 'mensagem-usuario' : 'mensagem-assistente'}`;
div.id = `msg_${mensagem.id}`;
const conteudoHtml = ehUsuario
? `<p>${escaparHtml(mensagem.conteudo).replace(/\n/g, '<br>')}</p>`
: markdownServico.converter(mensagem.conteudo);
div.innerHTML = `
<div class="mensagem-avatar">
${ehUsuario ? '👤' : '🤖'}
</div>
<div class="mensagem-conteudo">
<div class="mensagem-cabecalho">
<span class="mensagem-nome">${ehUsuario ? 'Você' : 'IA'}</span>
<span class="mensagem-hora">${formatarHora(mensagem.timestamp)}</span>
</div>
<div class="mensagem-texto">${conteudoHtml}</div>
<div class="mensagem-acoes">
<button class="botao-acao-mensagem" onclick="chat.copiarMensagem('${mensagem.id}')" title="Copiar">
📋 Copiar
</button>
</div>
</div>
`;
this._elementos.containerMensagens.appendChild(div);
},
/**
* Envia uma mensagem
*/
async _enviarMensagem() {
const texto = this._elementos.campoMensagem.value.trim();
if (!texto || this._enviando) return;
// Verifica API key (local ou global do servidor)
const apiKey = armazenamentoServico.obterApiKey();
const chaveGlobal = openrouterServico.obterChaveGlobalAtiva();
if (!apiKey && !chaveGlobal) {
toastErro('Configure sua API key nas configurações');
configuracoes.abrir();
return;
}
// Cria nova conversa se necessário
if (!this._conversaAtual) {
this._conversaAtual = {
id: gerarId(),
titulo: gerarTituloConversa(texto),
mensagens: [],
criadoEm: Date.now(),
atualizadoEm: Date.now(),
};
}
// Adiciona mensagem do usuário
const msgUsuario = {
id: gerarId(),
papel: 'user',
conteudo: texto,
timestamp: Date.now(),
};
this._conversaAtual.mensagens.push(msgUsuario);
this._conversaAtual.atualizadoEm = Date.now();
// Mostra o chat e limpa o campo
this._mostrarChat();
this._adicionarMensagemAoDOM(msgUsuario);
this._elementos.campoMensagem.value = '';
this._autoResize();
this._enviando = true;
this._atualizarBotaoEnviar();
this._salvarConversa();
barraLateral.renderizar();
rolarParaFinal(this._elementos.areaMensagens);
// Mostra indicador de digitando
const indicadorId = this._mostrarDigitando();
const modelo = armazenamentoServico.obterModelo();
const streaming = armazenamentoServico.obterStreaming();
try {
if (streaming) {
await this._enviarComStreaming(modelo, indicadorId);
} else {
await this._enviarSemStreaming(modelo, indicadorId);
}
} catch (erro) {
this._removerDigitando(indicadorId);
console.error('Erro ao enviar mensagem:', erro);
toastErro(erro.message || 'Erro ao comunicar com a IA');
// Adiciona mensagem de erro
const msgErro = {
id: gerarId(),
papel: 'assistant',
conteudo: `⚠️ **Erro:** ${erro.message || 'Erro desconhecido ao comunicar com a API.'}`,
timestamp: Date.now(),
};
this._conversaAtual.mensagens.push(msgErro);
this._adicionarMensagemAoDOM(msgErro);
} finally {
this._enviando = false;
this._atualizarBotaoEnviar();
this._salvarConversa();
rolarParaFinal(this._elementos.areaMensagens);
}
},
/**
* Envia sem streaming (resposta completa de uma vez)
*/
async _enviarSemStreaming(modelo, indicadorId) {
const resultado = await openrouterServico.enviarMensagem(
this._conversaAtual.mensagens,
modelo
);
this._removerDigitando(indicadorId);
const msgAssistente = {
id: gerarId(),
papel: 'assistant',
conteudo: resultado.conteudo,
timestamp: Date.now(),
};
this._conversaAtual.mensagens.push(msgAssistente);
this._adicionarMensagemAoDOM(msgAssistente);
},
/**
* Envia com streaming (palavra por palavra)
*/
async _enviarComStreaming(modelo, indicadorId) {
// Cria elemento da mensagem do assistente
const msgId = gerarId();
this._removerDigitando(indicadorId);
const div = document.createElement('div');
div.className = 'mensagem mensagem-assistente';
div.id = `msg_${msgId}`;
div.innerHTML = `
<div class="mensagem-avatar">🤖</div>
<div class="mensagem-conteudo">
<div class="mensagem-cabecalho">
<span class="mensagem-nome">IA</span>
<span class="mensagem-hora">Agora</span>
</div>
<div class="mensagem-texto" id="texto_${msgId}"><span class="cursor-streaming"></span></div>
<div class="mensagem-acoes">
<button class="botao-acao-mensagem" onclick="chat.copiarMensagem('${msgId}')" title="Copiar">
📋 Copiar
</button>
</div>
</div>
`;
this._elementos.containerMensagens.appendChild(div);
const elementoTexto = document.getElementById(`texto_${msgId}`);
let conteudoFinal = '';
await openrouterServico.enviarMensagemStream(
this._conversaAtual.mensagens,
modelo,
(delta, conteudoCompleto) => {
conteudoFinal = conteudoCompleto;
elementoTexto.innerHTML = markdownServico.converter(conteudoCompleto) + '<span class="cursor-streaming"></span>';
rolarParaFinal(this._elementos.areaMensagens);
}
);
// Remove cursor e renderiza final
elementoTexto.innerHTML = markdownServico.converter(conteudoFinal);
// Salva mensagem
const msgAssistente = {
id: msgId,
papel: 'assistant',
conteudo: conteudoFinal,
timestamp: Date.now(),
};
this._conversaAtual.mensagens.push(msgAssistente);
},
/**
* Mostra o indicador de "digitando..."
*/
_mostrarDigitando() {
const id = 'digitando_' + gerarId();
const div = document.createElement('div');
div.className = 'mensagem mensagem-assistente';
div.id = id;
div.innerHTML = `
<div class="mensagem-avatar">🤖</div>
<div class="mensagem-conteudo">
<div class="mensagem-cabecalho">
<span class="mensagem-nome">IA</span>
</div>
<div class="indicador-digitando">
<div class="ponto-digitando"></div>
<div class="ponto-digitando"></div>
<div class="ponto-digitando"></div>
</div>
</div>
`;
this._elementos.containerMensagens.appendChild(div);
rolarParaFinal(this._elementos.areaMensagens);
return id;
},
/**
* Remove o indicador de "digitando..."
*/
_removerDigitando(id) {
const elemento = document.getElementById(id);
if (elemento) elemento.remove();
},
/**
* Salva a conversa atual no armazenamento
*/
_salvarConversa() {
if (!this._conversaAtual) return;
const conversas = armazenamentoServico.obterConversas();
const indice = conversas.findIndex(c => c.id === this._conversaAtual.id);
if (indice >= 0) {
conversas[indice] = this._conversaAtual;
} else {
conversas.push(this._conversaAtual);
}
armazenamentoServico.salvarConversas(conversas);
armazenamentoServico.salvarConversaAtiva(this._conversaAtual.id);
},
/**
* Copia o conteúdo de uma mensagem
*/
async copiarMensagem(msgId) {
if (!this._conversaAtual) return;
const msg = this._conversaAtual.mensagens.find(m => m.id === msgId);
if (!msg) return;
const sucesso = await copiarParaClipboard(msg.conteudo);
if (sucesso) {
toastSucesso('Mensagem copiada!');
} else {
toastErro('Erro ao copiar mensagem');
}
},
};
